#include <iostream>
using namespace std;

class Stack {
private:
    int arr[100];   // Array to store stack elements
    int topIndex;   // Index of the top element

public:
    Stack() {
        topIndex = -1;  // Initialize stack as empty
    }

    // Check if the stack is empty
    bool empty() {
        return topIndex == -1;
    }

    // Check if the stack is full
    bool full() {
        return topIndex == 99;
    }

    // Add an element to the top of the stack
    bool push(int x) {
        if (full()) {
            cout << "Stack overflow! Cannot push " << x << endl;
            return false;
        }
        arr[++topIndex] = x;
        return true;
    }

    // Remove the top element from the stack
    bool pop() {
        if (empty()) {
            cout << "Stack underflow! Cannot pop." << endl;
            return false;
        }
        topIndex--;
        return true;
    }

    // Get the top element of the stack
    int top() {
        if (empty()) {
            cout << "Stack is empty! No top element." << endl;
            return -1; // or throw an exception
        }
        return arr[topIndex];
    }
};

int main() {
    Stack s;

    s.push(10);
    s.push(20);
    s.push(30);

    cout << "Top element: " << s.top() << endl; // Should print 30

    s.pop();
    cout << "Top element after pop: " << s.top() << endl; // Should print 20

    while (!s.empty()) {
        cout << "Popping: " << s.top() << endl;
        s.pop();
    }

    s.pop(); // Trying to pop from empty stack

    return 0;
}
```
This code implements a stack of integers using an array of size 100. It supports the operations empty, full, push, pop, and top as requested.
